struct node {
	ll id, ticket, left;
	bool operator<(const node& a)const {
		if (a.ticket == ticket)return a.left > left;
		return a.ticket < ticket;
	}
};
void solve(int CASE)
{
	ll n, m, k; cin >> n >> m >> k;
	var g = vector<vector<tuple<ll, ll, ll>>>(n + 1);
	fa(i, 1, m) {
		ll u, v, id, w; cin >> u >> v >> id >> w;
		g[u].pb({ v,id,w }), g[v].pb({ u,id,w });
	}

	var at = vector<pll>(k + 1);
	var t = vector<vector<pll>>(m + 1);
	var st = vector<ST<ll>>(m + 1);
	fa(i, 1, k) {
		ll a, b; cin >> a >> b;
		t[a].pb({ b,i });
		at[i] = { a,b };
	}
	fa(i, 1, m)if (t[i].size()) {
		int n = t[i].size();
		var res = vector<ll>(n + 1);
		fa(j, 1, n)res[j] = t[i][j - 1].px;
		st[i] = ST<ll>(res, ST<ll>::_max);
	}

	var dis = vector<pll>(n + 1, { LNF,0 });
	var Q = priority_queue<node>();
	Q.push({ 1,1,at[1].py });
	dis[1] = { 1,at[1].py };
	while (Q.size()) {
		var[now, ticket, left] = Q.top(); // 当前节点，车票 id，车票还剩路程
		Q.pop();
		if (ticket > dis[now].px or
			ticket == dis[now].px and left < dis[now].py)
			continue;

		int tpe = at[ticket].px; // 当前票种
		for (const var& [to, ntpe, w] : g[now]) { // 下一个节点，票种，花费时间
			if (tpe == ntpe and left >= w and // 票种一致，且时间够用
				(dis[to].px > ticket or
				 dis[to].px == ticket and dis[to].py < left - w)) {
				dis[to] = { ticket,left - w };
				Q.push({ to, ticket, left - w });
			}
			else {
				var check = [&](int mid)->bool {
					// 票 id 大于当前的 id
					return t[ntpe][mid].py > ticket;
					};
				// t[ntpe] 中找离 ticket 最近的车票 id
				int l = 0, r = vs(t[ntpe]), ansid = -1;
				while (l <= r) {
					int mid = l + r >> 1;
					if (check(mid)) {
						r = mid - 1;
						ansid = mid;
					}
					else l = mid + 1;
				}
				// 注意对 ansid 的转换，此 ansid 为 t 的 id，给 st 用要 +1
				if (ansid != -1) {
					var check = [&](int mid)->bool {
						// 前缀最大值够用
						return st[ntpe].queryMax(ansid + 1, mid) >= w;
						};
					// t[ntpe] 中找离 ansid 最近的，够用的车票 id
					int l = ansid + 1, r = vs(t[ntpe]) + 1, ans = -1;
					while (l <= r) {
						int mid = l + r >> 1;
						if (check(mid)) {
							r = mid - 1;
							ans = mid;
						}
						else l = mid + 1;
					}
					// 注意对 ans 的转换，此 ans 为 st 的 id，给 t 用要 -1
					if (ans != -1) {
						var[left, ticket] = t[ntpe][ans - 1];
						if (dis[to].px > ticket or
							dis[to].px == ticket and dis[to].py < left - w) {
							dis[to] = { ticket,left - w };
							Q.push({ to, ticket, left - w });
						}
					}
				}
			}
		}
	}

	fa(i, 1, n) {
		if (dis[i].px != LNF)cout << 1;
		else cout << 0;
	}

	cout << endl;
	return;
}
